const traces = [];

// 1. Line/Scatter (Row 1, Col 1 -> x, y)
traces.push({
  type: 'scatter',
  mode: 'lines+markers',
  x: [1, 2, 3, 4, 5],
  y: [2, 4, 1, 5, 3],
  name: 'Scatter',
  xaxis: 'x',
  yaxis: 'y',
  line: { color: '#0ea5e9', width: 3 },
  marker: { size: 8, color: '#38bdf8' }
});

// 2. Bar (Row 1, Col 2 -> x2, y2)
traces.push({
  type: 'bar',
  x: ['Apples', 'Oranges', 'Bananas'],
  y: [10, 15, 7],
  name: 'Bar',
  xaxis: 'x2',
  yaxis: 'y2',
  marker: { color: ['#ef4444', '#f97316', '#eab308'] }
});

// 3. Heatmap (Row 1, Col 3 -> x3, y3)
traces.push({
  type: 'heatmap',
  z: [[1, 20, 30], [20, 1, 60], [30, 60, 1]],
  name: 'Heatmap',
  xaxis: 'x3',
  yaxis: 'y3',
  colorscale: 'Viridis'
});

// 4. Pie / Donut (Row 2, Col 1 -> domain)
traces.push({
  type: 'pie',
  labels: ['Oxygen', 'Hydrogen', 'Carbon', 'Nitrogen'],
  values: [45, 25, 20, 10],
  domain: { row: 1, column: 0 },
  hole: 0.4,
  name: 'Donut'
});

// 5. Box Plot (Row 2, Col 2 -> x5, y5)
traces.push({
  type: 'box',
  y: [1, 2, 3, 4, 4, 4, 5, 5, 6, 8, 9, 2, 2, 1],
  name: 'Box',
  xaxis: 'x5',
  yaxis: 'y5',
  marker: { color: '#10b981' }
});

// 6. Treemap (Row 2, Col 3 -> domain)
traces.push({
  type: 'treemap',
  labels: ['Eve', 'Cain', 'Seth', 'Enos', 'Noam', 'Abel', 'Awan', 'Enoch', 'Azura'],
  parents: ['', 'Eve', 'Eve', 'Seth', 'Seth', 'Eve', 'Eve', 'Awan', 'Eve'],
  values: [10, 14, 12, 10, 2, 6, 6, 4, 4],
  domain: { row: 1, column: 2 },
  textinfo: 'label+value',
  marker: { colorscale: 'Blues' }
});

// 7. Contour Plot (Row 3, Col 1 -> x7, y7)
traces.push({
  type: 'contour',
  z: [[10, 10.6, 12, 11], [10.6, 12, 10, 13], [12, 10, 10.6, 11], [11, 13, 11, 12]],
  name: 'Contour',
  xaxis: 'x7',
  yaxis: 'y7',
  colorscale: 'Jet'
});

// 8. 3D Scatter (Since 3D needs explicit scene, let's use a 3D plot instead of Candlestick to show 3D support if possible. Wait, 3D plots don't work well in Cartesian grid subplots. Let's stick to Area.)
// 8. Area Chart (Row 3, Col 2 -> x8, y8)
traces.push({
  type: 'scatter',
  mode: 'none',
  fill: 'tozeroy',
  x: [1, 2, 3, 4],  
  y: [0, 2, 3, 1],
  name: 'Area',
  xaxis: 'x8',
  yaxis: 'y8',
  fillcolor: 'rgba(168, 85, 247, 0.5)'
});

// 9. Violin Plot (Row 3, Col 3 -> x9, y9)
traces.push({
  type: 'violin',
  y: [2, 2, 3, 4, 5, 5, 5, 6, 7, 7, 8, 9, 10],
  name: 'Violin',
  xaxis: 'x9',
  yaxis: 'y9',
  box: { visible: true },
  line: { color: 'white' },
  meanline: { visible: true },
  fillcolor: '#f43f5e'
});

return traces;
